1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 10;
3	const PERCENT_BASE = 100;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const INSURANCE_VALUE: Record<string, number> = {
15	  sword: 1000,
16	  amulet: 600,
17	  staff: 800,
18	  potion: 400,
19	  rune: 250,
20	  moonstone: 250,
21	};
22	
23	const DEDUCTIBLE = 100;
24	const CAP_MULTIPLIER = 2;
25	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
26	const HIGH_ENCHANTMENT_PAYOUT_RATIO = 0.5;
27	
28	interface Item {
29	  type: string;
30	  cursed?: boolean;
31	  enchantment?: number;
32	  material?: string;
33	}
34	
35	interface Damage {
36	  itemType: string;
37	  amount: number;
38	}
39	
40	interface Incident {
41	  cause?: string;
42	  damages: Damage[];
43	}
44	
45	interface Step {
46	  op: string;
47	  items?: Item[];
48	  policy?: number;
49	  incident?: Incident;
50	}
51	
52	interface Customer {
53	  yearsWithMHPCO: number;
54	}
55	
56	interface Scenario {
57	  customer: Customer;
58	  steps: Step[];
59	}
60	
61	const BLOCK_SIZE = 3;
62	const BLOCK_PREMIUM = 60;
63	const CURSE_SURCHARGE_PERCENT = 50;
64	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
65	const HIGH_ENCHANTMENT_THRESHOLD = 5;
66	const LOYALTY_DISCOUNT_PERCENT = 20;
67	const LOYALTY_THRESHOLD_YEARS = 2;
68	const FOLLOWUP_DISCOUNT_PERCENT = 15;
69	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
70	
71	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
72	
73	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
74	
75	const percentOf = (amount: number, percent: number): number =>
76	  (amount * percent) / PERCENT_BASE;
77	
78	const percentIf = (condition: boolean, base: number, percent: number): number =>
79	  condition ? percentOf(base, percent) : 0;
80	
81	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type];
82	
83	const itemSurcharges = (item: Item): number => {
84	  const base = itemBasePremium(item);
85	  const curse = percentIf(item.cursed === true, base, CURSE_SURCHARGE_PERCENT);
86	  const highEnchantment = percentIf(
87	    enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD,
88	    base,
89	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
90	  );
91	  return curse + highEnchantment;
92	};
93	
94	const sumItemBases = (items: Item[]): number =>
95	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
96	
97	const sumSurcharges = (items: Item[]): number =>
98	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
99	
100	const partitionByType = (items: Item[]): Item[][] => {
101	  const groups: Record<string, Item[]> = {};
102	  items.forEach((item) => (groups[item.type] ??= []).push(item));
103	  return Object.values(groups);
104	};
105	
106	const isComponentBlock = (group: Item[]): boolean =>
107	  group.length === BLOCK_SIZE && isComponent(group[0]);
108	
109	const priceGroup = (group: Item[]): number =>
110	  isComponentBlock(group) ? BLOCK_PREMIUM : sumItemBases(group);
111	
112	const sumBasePremiums = (items: Item[]): number =>
113	  partitionByType(items).reduce((sum, group) => sum + priceGroup(group), 0);
114	
115	const isLoyalCustomer = (customer: Customer): boolean =>
116	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
117	
118	const applyPolicyModifiers = (
119	  base: number,
120	  customer: Customer,
121	  isFollowUp: boolean,
122	): number => {
123	  const firstInsurance = percentOf(base, FIRST_INSURANCE_PERCENT);
124	  const loyalty = percentIf(isLoyalCustomer(customer), base, LOYALTY_DISCOUNT_PERCENT);
125	  const followUp = percentIf(isFollowUp, base, FOLLOWUP_DISCOUNT_PERCENT);
126	  return base + firstInsurance - loyalty - followUp;
127	};
128	
129	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
130	  const policyBase = sumBasePremiums(items);
131	  const surcharges = sumSurcharges(items);
132	  return Math.ceil(applyPolicyModifiers(policyBase, customer, isFollowUp) + surcharges) + PROCESSING_FEE;
133	};
134	
135	const policyInsuranceSum = (items: Item[]): number =>
136	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
137	
138	const isHighEnchantmentClaim = (item: Item): boolean =>
139	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
140	
141	const reimbursableAmount = (damage: Damage, item: Item): number =>
142	  isHighEnchantmentClaim(item)
143	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATIO
144	    : damage.amount;
145	
146	const damagePayout = (damage: Damage, item: Item): number =>
147	  Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE);
148	
149	const findPolicyItem = (policyItems: Item[], itemType: string): Item =>
150	  policyItems.find((i) => i.type === itemType) as Item;
151	
152	const totalClaimCap = (policyItems: Item[]): number =>
153	  policyInsuranceSum(policyItems) * CAP_MULTIPLIER;
154	
155	const sumDamagePayouts = (damages: Damage[], policyItems: Item[]): number =>
156	  damages.reduce(
157	    (sum, d) => sum + damagePayout(d, findPolicyItem(policyItems, d.itemType)),
158	    0,
159	  );
160	
161	const processClaim = (
162	  step: Step,
163	  policyItems: Item[],
164	  remainingCap: number,
165	): { payout: number; remainingCap: number } => {
166	  const desired = sumDamagePayouts(step.incident?.damages ?? [], policyItems);
167	  const payout = Math.min(desired, remainingCap);
168	  return { payout, remainingCap: remainingCap - payout };
169	};
170	
171	const isQuote = (step: Step): boolean => step.op === "quote";
172	
173	const isClaim = (step: Step): boolean => step.op === "claim";
174	
175	const hasPriorQuote = (steps: Step[], index: number): boolean =>
176	  steps.slice(0, index).some(isQuote);
177	
178	const policyItemsFor = (step: Step, steps: Step[]): Item[] =>
179	  steps[step.policy ?? 0].items ?? [];
180	
181	export const runScenario = (input: unknown): { results: unknown[] } => {
182	  const scenario = input as Scenario;
183	  const remainingCaps: Record<number, number> = {};
184	  const results = scenario.steps.map((step, index) => {
185	    if (isClaim(step)) {
186	      const policyIndex = step.policy ?? 0;
187	      const policyItems = scenario.steps[policyIndex].items ?? [];
188	      remainingCaps[policyIndex] ??= totalClaimCap(policyItems);
189	      const result = processClaim(step, policyItems, remainingCaps[policyIndex]);
190	      remainingCaps[policyIndex] = result.remainingCap;
191	      return result;
192	    }
193	    return {
194	      premium: quotePremium(
195	        step.items ?? [],
196	        scenario.customer,
197	        hasPriorQuote(scenario.steps, index),
198	      ),
199	    };
200	  });
201	  return { results };
202	};
